# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 00 Workflow 계획 파서
# 역할: inline JSON/Markdown 또는 Workflow Registry 로더 후보를 최대 4단계 workflow.plan.v1 계약으로 정규화합니다.
# 주요 입력: Workflow 정의, Workflow 키, Workflow JSON Registry, 사용자 원문 질문, 허용 Tool 이름·capability
# 주요 출력: 검증 결과 Data, 기본 Langflow Loop용 DataFrame, Loop용 Data 목록
# 처리 흐름: 후보 registry 우선 해석 -> JSON/Markdown 파싱 -> 등록 key 재확정 -> 필드 정규화 -> dependency/handoff/on_error 검증 -> Loop 행 생성
# 유지보수 포인트: DB 조회는 00A가 담당하며 이 Parser는 모호한 registry·미래 dependency·4단계 초과를 실행 전에 차단합니다.
# =============================================================================

from __future__ import annotations

import json
import re
import uuid
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, MultilineInput, Output
from lfx.schema.data import Data
from lfx.schema.dataframe import DataFrame

PLAN_CONTRACT_VERSION = "workflow.plan.v1"
MAX_WORKFLOW_STEPS = 4
MAX_QUESTION_CHARS = 4000
STEP_ID_PATTERN = re.compile(r"^[A-Za-z][A-Za-z0-9_-]{0,63}$")
TOOL_NAME_PATTERN = re.compile(r"^[A-Za-z][A-Za-z0-9_-]{0,99}$")
ALLOWED_HANDOFFS = {"none", "result_ref"}
ALLOWED_ON_ERROR = {"stop", "continue"}


# 주요 함수: 입력 정의와 registry를 해석해 실행 가능 여부, 정규화 계획, 오류를 하나의 표준 결과로 반환합니다.
def parse_workflow_plan(
    workflow_input: Any = "",
    workflow_key: Any = "",
    workflow_registry_json: Any = "",
    user_question: Any = "",
    allowed_tools_value: Any = None,
    workflow_run_id: Any = "",
    tool_capabilities_value: Any = None,
) -> dict[str, Any]:
    errors: list[dict[str, Any]] = []
    requested_key = str(workflow_key or "").strip()
    source_value = _text(workflow_input)
    registry_value, registry_errors = _parse_registry(workflow_registry_json)
    errors.extend(registry_errors)

    # Playground에 registry key만 입력한 경우에는 계획 모델 출력보다 등록 정의를 우선합니다.
    # 한국어 자연어 질문은 key 형식과 다르고, 영문 단어가 미등록 key이면 기존 모델 계획을 그대로 해석합니다.
    question_text = _text(user_question).strip()
    question_key = _inline_workflow_key(question_text)
    inline_key = _inline_workflow_key(source_value)
    selected_key = requested_key
    raw_plan: Any = None
    source_kind = "inline"
    if requested_key:
        raw_plan, lookup_errors = _lookup_registry_workflow(registry_value, selected_key)
        errors.extend(lookup_errors)
        if isinstance(raw_plan, dict) and raw_plan:
            selected_key = str(raw_plan.get("workflow_key") or selected_key).strip()
        source_kind = "registry"
    elif question_text and not errors:
        registered_plan, question_lookup_errors = _lookup_registry_identifier(registry_value, question_text)
        if not question_lookup_errors:
            selected_key = str(registered_plan.get("workflow_key") or question_key).strip()
            raw_plan = registered_plan
            source_kind = "registry"
    if raw_plan is None and inline_key:
        selected_key = inline_key
        raw_plan, lookup_errors = _lookup_registry_workflow(registry_value, selected_key)
        errors.extend(lookup_errors)
        source_kind = "registry"
    elif raw_plan is None and not errors:
        raw_plan, parse_errors = _parse_inline_workflow(source_value)
        errors.extend(parse_errors)

    # 계획 모델이 등록 key와 함께 단계를 다시 작성했더라도 현재 Registry의 canonical 정의를 실행합니다.
    # 미등록 key나 workflow_key=inline은 동적 inline 계획으로 유지해 Registry 장애를 seed fallback으로 숨기지 않습니다.
    if isinstance(raw_plan, dict) and raw_plan and source_kind == "inline":
        planned_key = str(raw_plan.get("workflow_key") or raw_plan.get("key") or "").strip()
        if planned_key and planned_key.lower() != "inline":
            registered_plan, planned_lookup_errors = _lookup_registry_workflow(registry_value, planned_key)
            if not planned_lookup_errors:
                raw_plan = registered_plan
                selected_key = str(registered_plan.get("workflow_key") or planned_key).strip()
                source_kind = "registry"

    if not isinstance(raw_plan, dict):
        raw_plan = {}
    normalized = normalize_workflow_plan(
        raw_plan,
        user_question=user_question,
        selected_workflow_key=selected_key,
        workflow_run_id=workflow_run_id,
    )
    normalized, normalizations = normalize_handoff_semantics(normalized, tool_capabilities_value)
    errors.extend(validate_workflow_plan(normalized, allowed_tools_value, tool_capabilities_value))
    status = "error" if errors else "ok"
    if status == "error":
        # invalid step을 Loop로 보내지 않도록 실제 실행용 steps는 빈 목록으로 닫습니다.
        executable_plan = deepcopy(normalized)
        executable_plan["steps"] = []
    else:
        executable_plan = normalized
    return {
        "status": status,
        "contract_version": PLAN_CONTRACT_VERSION,
        "workflow_plan": executable_plan,
        "normalized_plan": normalized,
        "source_kind": source_kind,
        "normalizations": normalizations,
        "errors": errors,
    }


# 주요 함수: 여러 입력 형태의 필드를 고정 workflow.plan.v1 이름과 자료형으로 변환합니다.
def normalize_workflow_plan(
    raw_plan: Any,
    *,
    user_question: Any = "",
    selected_workflow_key: Any = "",
    workflow_run_id: Any = "",
) -> dict[str, Any]:
    source = deepcopy(raw_plan) if isinstance(raw_plan, dict) else {}
    question = str(user_question or "").strip()
    raw_steps = source.get("steps") if isinstance(source.get("steps"), list) else []
    steps: list[dict[str, Any]] = []
    for index, raw_step in enumerate(raw_steps):
        step = raw_step if isinstance(raw_step, dict) else {}
        depends_on = _string_list(step.get("depends_on"))
        step_question = str(step.get("question") or "").strip()
        if question:
            step_question = step_question.replace("{{user_question}}", question).replace("${user_question}", question)
        steps.append(
            {
                "step_index": index + 1,
                "step_id": str(step.get("step_id") or step.get("id") or "").strip(),
                "tool_name": str(step.get("tool_name") or step.get("tool") or "").strip(),
                "question": step_question,
                "depends_on": depends_on,
                "handoff": str(step.get("handoff") or "none").strip().lower(),
                "on_error": str(step.get("on_error") or "stop").strip().lower(),
            }
        )
    key = str(selected_workflow_key or source.get("workflow_key") or source.get("key") or "inline").strip()
    run_id = str(workflow_run_id or "").strip() or f"workflow:{uuid.uuid4().hex}"
    return {
        "contract_version": PLAN_CONTRACT_VERSION,
        "workflow_run_id": run_id,
        "workflow_key": key,
        "title": str(source.get("title") or source.get("display_name") or key).strip(),
        "description": str(source.get("description") or "").strip(),
        "user_question": question,
        "max_steps": MAX_WORKFLOW_STEPS,
        "steps": steps,
    }


# 주요 함수: capability가 명확한 단일 producer→consumer 관계에서 모델이 handoff를 producer에 둔 경우만 안전하게 바로잡습니다.
# 여러 consumer가 있거나 capability가 없으면 추측하지 않고 기존 strict validation에 맡깁니다.
def normalize_handoff_semantics(
    plan: Any,
    tool_capabilities_value: Any = None,
) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    normalized = deepcopy(plan) if isinstance(plan, dict) else {}
    steps = normalized.get("steps") if isinstance(normalized.get("steps"), list) else []
    capabilities = _tool_capabilities(tool_capabilities_value)
    normalizations: list[dict[str, Any]] = []

    for producer in steps:
        if not isinstance(producer, dict):
            continue
        if str(producer.get("handoff") or "none").strip().lower() != "result_ref":
            continue
        if _string_list(producer.get("depends_on")):
            continue
        producer_id = str(producer.get("step_id") or "").strip()
        producer_tool = str(producer.get("tool_name") or "").strip()
        producer_capability = capabilities.get(producer_tool, {})
        if not producer_id or producer_capability.get("can_produce_result_ref") is not True:
            continue

        consumers: list[dict[str, Any]] = []
        for candidate in steps:
            if not isinstance(candidate, dict) or candidate is producer:
                continue
            candidate_tool = str(candidate.get("tool_name") or "").strip()
            candidate_capability = capabilities.get(candidate_tool, {})
            if candidate_capability.get("requires_upstream_result_ref") is not True:
                continue
            if _string_list(candidate.get("depends_on")) != [producer_id]:
                continue
            if str(candidate.get("handoff") or "none").strip().lower() != "none":
                continue
            consumers.append(candidate)

        if len(consumers) != 1:
            continue
        consumer = consumers[0]
        producer["handoff"] = "none"
        consumer["handoff"] = "result_ref"
        normalizations.append(
            {
                "type": "inverted_result_ref_handoff_normalized",
                "message": "result_ref handoff를 결과 생성 단계가 아니라 해당 결과를 입력으로 받는 단계에 적용했습니다.",
                "producer_step_id": producer_id,
                "consumer_step_id": str(consumer.get("step_id") or "").strip(),
            }
        )
    return normalized, normalizations


# 주요 함수: 단계 수·이름·질문·dependency 순서·handoff·오류 정책을 검사하고 모든 위반을 표준 오류 목록으로 반환합니다.
def validate_workflow_plan(
    plan: Any,
    allowed_tools_value: Any = None,
    tool_capabilities_value: Any = None,
) -> list[dict[str, Any]]:
    errors: list[dict[str, Any]] = []
    value = plan if isinstance(plan, dict) else {}
    steps = value.get("steps") if isinstance(value.get("steps"), list) else []
    allowed_tools = set(_allowed_tools(allowed_tools_value))
    capabilities = _tool_capabilities(tool_capabilities_value)
    if not steps:
        errors.append(_issue("workflow_steps_missing", "Workflow에는 실행 단계가 1개 이상 필요합니다."))
        return errors
    if len(steps) > MAX_WORKFLOW_STEPS:
        errors.append(
            _issue(
                "workflow_step_limit_exceeded",
                f"Workflow 단계는 최대 {MAX_WORKFLOW_STEPS}개까지 허용됩니다.",
                step_count=len(steps),
                max_steps=MAX_WORKFLOW_STEPS,
            )
        )

    seen_ids: set[str] = set()
    seen_step_tools: dict[str, str] = {}
    for index, step_value in enumerate(steps):
        step = step_value if isinstance(step_value, dict) else {}
        step_id = str(step.get("step_id") or "").strip()
        tool_name = str(step.get("tool_name") or "").strip()
        question = str(step.get("question") or "").strip()
        depends_on = _string_list(step.get("depends_on"))
        handoff = str(step.get("handoff") or "").strip().lower()
        on_error = str(step.get("on_error") or "").strip().lower()
        location = {"index": index, "step_id": step_id}

        if not STEP_ID_PATTERN.fullmatch(step_id):
            errors.append(_issue("invalid_step_id", "step_id는 영문자로 시작하는 영문·숫자·밑줄·하이픈이어야 합니다.", **location))
        elif step_id in seen_ids:
            errors.append(_issue("duplicate_step_id", f"step_id가 중복되었습니다: {step_id}", **location))
        if not TOOL_NAME_PATTERN.fullmatch(tool_name):
            errors.append(_issue("invalid_tool_name", "tool_name 형식이 올바르지 않습니다.", tool_name=tool_name, **location))
        elif allowed_tools and tool_name not in allowed_tools:
            errors.append(_issue("unregistered_tool_name", f"허용 Tool 목록에 없는 tool_name입니다: {tool_name}", tool_name=tool_name, **location))
        if not question:
            errors.append(_issue("step_question_missing", "각 단계에는 실행할 question이 필요합니다.", **location))
        elif len(question) > MAX_QUESTION_CHARS:
            errors.append(_issue("step_question_too_long", f"단계 question은 {MAX_QUESTION_CHARS}자를 초과할 수 없습니다.", **location))
        if handoff not in ALLOWED_HANDOFFS:
            errors.append(_issue("invalid_handoff", f"handoff는 {', '.join(sorted(ALLOWED_HANDOFFS))} 중 하나여야 합니다.", **location))
        if on_error not in ALLOWED_ON_ERROR:
            errors.append(_issue("invalid_on_error", f"on_error는 {', '.join(sorted(ALLOWED_ON_ERROR))} 중 하나여야 합니다.", **location))
        if len(depends_on) != len(set(depends_on)):
            errors.append(_issue("duplicate_dependency", "depends_on에 같은 step_id가 중복되었습니다.", **location))
        for dependency in depends_on:
            if dependency == step_id:
                errors.append(_issue("self_dependency", "단계는 자기 자신에 의존할 수 없습니다.", dependency=dependency, **location))
            elif dependency not in seen_ids:
                errors.append(
                    _issue(
                        "future_or_unknown_dependency",
                        f"depends_on은 앞에서 정의된 step_id만 참조할 수 있습니다: {dependency}",
                        dependency=dependency,
                        **location,
                    )
                )
        if index == 0 and depends_on:
            errors.append(_issue("first_step_dependency_not_allowed", "첫 단계에는 depends_on을 지정할 수 없습니다.", **location))
        if index == 0 and handoff != "none":
            errors.append(_issue("first_step_handoff_not_allowed", "첫 단계의 handoff는 none이어야 합니다.", **location))
        if handoff == "result_ref" and len(depends_on) != 1:
            errors.append(_issue("ambiguous_result_ref_handoff", "result_ref handoff에는 depends_on이 정확히 1개여야 합니다.", **location))
        capability = capabilities.get(tool_name, {})
        requires_ref = capability.get("requires_upstream_result_ref") is True
        accepts_ref = capability.get("accepts_upstream_result_ref") is True
        if requires_ref and handoff != "result_ref":
            errors.append(
                _issue(
                    "required_result_ref_handoff_missing",
                    f"{tool_name} 단계는 이전 분석 결과를 입력으로 받아야 하므로 handoff=result_ref가 필요합니다.",
                    tool_name=tool_name,
                    **location,
                )
            )
        if handoff == "result_ref" and capability and not accepts_ref:
            errors.append(
                _issue(
                    "tool_cannot_accept_result_ref",
                    f"{tool_name} Tool은 upstream_result_ref 입력을 지원하지 않습니다.",
                    tool_name=tool_name,
                    **location,
                )
            )
        if handoff == "result_ref" and len(depends_on) == 1:
            dependency = depends_on[0]
            dependency_tool = seen_step_tools.get(dependency, "")
            dependency_capability = capabilities.get(dependency_tool, {})
            if dependency_capability and dependency_capability.get("can_produce_result_ref") is not True:
                errors.append(
                    _issue(
                        "dependency_cannot_produce_result_ref",
                        f"{dependency_tool} Tool은 다음 단계에 전달할 result_ref를 생성하지 않습니다.",
                        dependency=dependency,
                        dependency_tool_name=dependency_tool,
                        **location,
                    )
                )
        seen_ids.add(step_id)
        seen_step_tools[step_id] = tool_name
    return errors


# 함수 설명: `_parse_inline_workflow()`는 JSON, fenced JSON, 지정된 간단 Markdown 형식을 순서대로 해석합니다.
def _parse_inline_workflow(value: str) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    if not value.strip():
        return {}, [_issue("workflow_input_missing", "inline Workflow 정의 또는 workflow_key가 필요합니다.")]
    json_values = _json_candidates(value)
    if len(json_values) == 1 and isinstance(json_values[0], dict):
        return json_values[0], []
    if len(json_values) > 1:
        return {}, [_issue("ambiguous_inline_json", "inline 입력에서 둘 이상의 Workflow JSON을 발견했습니다.")]
    markdown_plan = _parse_markdown_plan(value)
    if markdown_plan.get("steps"):
        return markdown_plan, []
    return {}, [_issue("workflow_parse_error", "Workflow를 JSON 또는 지원 Markdown 형식으로 해석하지 못했습니다.")]


# 함수 설명: `_json_candidates()`는 전체 문자열과 fenced code block에서 object JSON만 중복 없이 찾습니다.
def _json_candidates(value: str) -> list[dict[str, Any]]:
    texts = [value.strip()]
    texts.extend(match.group(1).strip() for match in re.finditer(r"```(?:json)?\s*([\s\S]*?)```", value, re.IGNORECASE))
    result: list[dict[str, Any]] = []
    markers: set[str] = set()
    for text in texts:
        try:
            parsed = json.loads(text)
        except (TypeError, ValueError, json.JSONDecodeError):
            continue
        if not isinstance(parsed, dict):
            continue
        marker = json.dumps(parsed, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
        if marker not in markers:
            markers.add(marker)
            result.append(parsed)
    return result


# 함수 설명: `_parse_markdown_plan()`은 문서에 명시한 heading/key-value 형식만 보수적으로 Workflow dict로 변환합니다.
def _parse_markdown_plan(value: str) -> dict[str, Any]:
    result: dict[str, Any] = {"steps": []}
    current_step: dict[str, Any] | None = None
    for raw_line in value.splitlines():
        line = raw_line.strip()
        if not line or line.startswith("<!--") or line in {"---", "## steps", "## Steps"}:
            continue
        heading = re.match(r"^#{2,6}\s+(?:step\s*[:：]\s*)?([A-Za-z][A-Za-z0-9_-]{0,63})\s*$", line, re.IGNORECASE)
        if heading:
            if current_step:
                result["steps"].append(current_step)
            current_step = {"step_id": heading.group(1)}
            continue
        cleaned = re.sub(r"^(?:[-*+]\s+|\d+[.)]\s+)", "", line)
        match = re.match(r"^([A-Za-z_][A-Za-z0-9_-]*)\s*[:：]\s*(.*)$", cleaned)
        if not match:
            continue
        key, raw_value = match.group(1).lower(), match.group(2).strip()
        parsed_value: Any = _markdown_value(raw_value) if key == "depends_on" else raw_value.strip("`\"")
        if key == "step_id":
            if current_step and current_step.get("step_id"):
                result["steps"].append(current_step)
            current_step = {"step_id": str(parsed_value)}
        elif key in {"tool_name", "question", "depends_on", "handoff", "on_error"}:
            if current_step is None:
                current_step = {}
            current_step[key] = parsed_value
        elif key in {"workflow_key", "title", "description"}:
            result[key] = parsed_value
    if current_step:
        result["steps"].append(current_step)
    return result


# 함수 설명: `_markdown_value()`는 depends_on의 JSON 배열, 쉼표 목록, none 표현을 문자열 목록으로 바꿉니다.
def _markdown_value(value: str) -> list[str]:
    text = value.strip()
    if text.lower() in {"", "none", "null", "[]", "없음"}:
        return []
    try:
        parsed = json.loads(text)
    except (TypeError, ValueError, json.JSONDecodeError):
        parsed = [item.strip() for item in text.strip("[]").split(",")]
    return _string_list(parsed)


# 함수 설명: `_parse_registry()`는 standalone 화면 입력의 JSON만 읽고 다른 외부 저장소나 환경변수를 참조하지 않습니다.
def _parse_registry(value: Any) -> tuple[Any, list[dict[str, Any]]]:
    text = _text(value).strip()
    if not text:
        return {}, []
    try:
        parsed = json.loads(text)
    except (TypeError, ValueError, json.JSONDecodeError) as exc:
        return {}, [_issue("workflow_registry_parse_error", f"Workflow Registry JSON 형식이 올바르지 않습니다: {exc}")]
    if not isinstance(parsed, (dict, list)):
        return {}, [_issue("invalid_workflow_registry", "Workflow Registry는 object 또는 array여야 합니다.")]
    return parsed, []


# 함수 설명: `_lookup_registry_workflow()`는 지원 registry 형태에서 정확히 한 개의 workflow_key만 선택합니다.
def _lookup_registry_workflow(registry: Any, workflow_key: str) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    candidates: list[dict[str, Any]] = []
    source = registry.get("workflows") if isinstance(registry, dict) and "workflows" in registry else registry
    if isinstance(source, dict):
        direct = source.get(workflow_key)
        if isinstance(direct, dict):
            candidates.append(deepcopy(direct))
        for key, item in source.items():
            if not isinstance(item, dict) or key == workflow_key:
                continue
            item_key = str(item.get("workflow_key") or item.get("key") or "").strip()
            if item_key == workflow_key:
                candidates.append(deepcopy(item))
    elif isinstance(source, list):
        candidates.extend(
            deepcopy(item)
            for item in source
            if isinstance(item, dict)
            and str(item.get("workflow_key") or item.get("key") or "").strip() == workflow_key
        )
    if not candidates:
        return {}, [_issue("workflow_key_not_found", f"Workflow Registry에서 key를 찾지 못했습니다: {workflow_key}")]
    if len(candidates) > 1:
        return {}, [_issue("duplicate_workflow_key", f"Workflow Registry에 같은 key가 둘 이상 있습니다: {workflow_key}")]
    selected = candidates[0]
    selected.setdefault("workflow_key", workflow_key)
    return selected, []


# 함수 설명: `_lookup_registry_identifier()`는 canonical key를 먼저 찾고 없을 때만 정규화된 alias 정확 일치를 허용합니다.
def _lookup_registry_identifier(registry: Any, identifier: str) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    exact, exact_errors = _lookup_registry_workflow(registry, identifier)
    if not exact_errors:
        return exact, []
    normalized = _normalized_identifier(identifier)
    if not normalized:
        return {}, exact_errors
    source = registry.get("workflows") if isinstance(registry, dict) and "workflows" in registry else registry
    values = list(source.values()) if isinstance(source, dict) else source if isinstance(source, list) else []
    candidates: list[dict[str, Any]] = []
    for item in values:
        if not isinstance(item, dict):
            continue
        aliases = _string_list(item.get("aliases"))
        if any(_normalized_identifier(alias) == normalized for alias in aliases):
            candidates.append(deepcopy(item))
    if not candidates:
        return {}, exact_errors
    if len(candidates) > 1:
        return {}, [_issue("duplicate_workflow_alias", f"Workflow Registry에 같은 alias가 둘 이상 있습니다: {identifier}")]
    selected = candidates[0]
    canonical = str(selected.get("workflow_key") or selected.get("key") or "").strip()
    if not canonical:
        return {}, [_issue("workflow_key_missing", "alias가 일치한 Workflow에 canonical key가 없습니다.")]
    selected.setdefault("workflow_key", canonical)
    return selected, []


# 함수 설명: `_normalized_identifier()`는 key/alias 정확 비교에서 공백과 영문 대소문자 차이를 제거합니다.
def _normalized_identifier(value: Any) -> str:
    return re.sub(r"\s+", "", str(value or "").strip().lower())


# 함수 설명: `_inline_workflow_key()`는 JSON 본문이 아닌 key-only 입력에서 registry 조회용 workflow_key를 추출합니다.
def _inline_workflow_key(value: str) -> str:
    stripped = value.strip()
    match = re.fullmatch(r"(?:workflow_key\s*[:：]\s*)?([A-Za-z][A-Za-z0-9_.-]{0,127})", stripped, re.IGNORECASE)
    return match.group(1) if match else ""


# 함수 설명: `_allowed_tools()`는 JSON 배열·쉼표·줄바꿈 형식의 허용 Tool 이름을 중복 없는 목록으로 정리합니다.
def _allowed_tools(value: Any) -> list[str]:
    data = getattr(value, "data", value)
    if isinstance(data, dict):
        data = data.get("tools") or data.get("allowed_tools") or []
    if isinstance(data, str):
        text = data.strip()
        try:
            parsed = json.loads(text)
        except (TypeError, ValueError, json.JSONDecodeError):
            parsed = re.split(r"[,\n]", text)
        data = parsed
    return _string_list(data)


# 함수 설명: `_tool_capabilities()`는 Tool catalog를 이름별 result_ref 생성·소비 계약으로 정규화합니다.
def _tool_capabilities(value: Any) -> dict[str, dict[str, bool]]:
    data = getattr(value, "data", value)
    if isinstance(data, str):
        try:
            data = json.loads(data.strip() or "[]")
        except (TypeError, ValueError, json.JSONDecodeError):
            return {}
    if isinstance(data, dict):
        data = data.get("tools") or data.get("tool_capabilities") or data.get("catalog") or []
    if not isinstance(data, list):
        return {}

    result: dict[str, dict[str, bool]] = {}
    for item in data:
        if not isinstance(item, dict):
            continue
        tool_name = str(item.get("tool_name") or item.get("name") or "").strip()
        if not tool_name:
            continue
        accepts = item.get("accepts_upstream_result_ref") is True
        requires = item.get("requires_upstream_result_ref") is True
        result[tool_name] = {
            "accepts_upstream_result_ref": accepts or requires,
            "requires_upstream_result_ref": requires,
            "can_produce_result_ref": item.get("can_produce_result_ref") is True,
        }
    return result


# 함수 설명: `_string_list()`는 문자열·목록 입력을 비어 있지 않은 중복 없는 문자열 목록으로 정규화합니다.
def _string_list(value: Any) -> list[str]:
    if isinstance(value, str):
        values = [value]
    elif isinstance(value, (list, tuple, set)):
        values = list(value)
    else:
        values = []
    result: list[str] = []
    for item in values:
        text = str(item or "").strip()
        if text and text not in result:
            result.append(text)
    return result


# 함수 설명: `_loop_rows()`는 검증된 계획의 각 단계를 Loop가 읽을 text key와 실행 context가 있는 한 행으로 변환합니다.
def _loop_rows(parse_result: dict[str, Any]) -> list[dict[str, Any]]:
    if str(parse_result.get("status")) != "ok":
        return []
    plan = parse_result.get("workflow_plan") if isinstance(parse_result.get("workflow_plan"), dict) else {}
    steps = plan.get("steps") if isinstance(plan.get("steps"), list) else []
    rows: list[dict[str, Any]] = []
    for step in steps:
        row = {
            "contract_version": PLAN_CONTRACT_VERSION,
            "workflow_run_id": plan.get("workflow_run_id"),
            "workflow_key": plan.get("workflow_key"),
            "workflow_title": plan.get("title"),
            "original_question": plan.get("user_question"),
            "total_steps": len(steps),
            **deepcopy(step),
        }
        row["text"] = json.dumps(row, ensure_ascii=False, separators=(",", ":"))
        rows.append(row)
    return rows


# 함수 설명: `_text()`는 Langflow Message/Data 또는 일반 값을 parser가 읽을 문자열로 변환합니다.
def _text(value: Any) -> str:
    if isinstance(value, str):
        return value
    text = getattr(value, "text", None)
    if text is not None:
        return str(text)
    data = getattr(value, "data", value)
    if isinstance(data, (dict, list)):
        return json.dumps(data, ensure_ascii=False)
    return str(data or "")


# 함수 설명: `_issue()`는 파싱·검증 오류를 type/message와 선택 위치 정보가 있는 dict로 만듭니다.
def _issue(issue_type: str, message: str, **extra: Any) -> dict[str, Any]:
    return {"type": issue_type, "message": message, **extra}


# Langflow 컴포넌트 클래스: standalone 화면의 registry/inline 입력과 기본 Loop가 사용할 두 자료형 출력을 함께 제공합니다.
class WorkflowPlanParser(Component):
    display_name = "00 Workflow 계획 파서"
    description = "inline JSON/Markdown 또는 화면 JSON Registry를 최대 4단계 workflow.plan.v1로 검증합니다."
    name = "WorkflowPlanParser"
    icon = "ListChecks"

    inputs = [
        MultilineInput(
            name="workflow_input",
            display_name="Inline Workflow 정의",
            info="JSON, fenced JSON 또는 작성 가이드의 Markdown 형식입니다. workflow_key 사용 시 비워도 됩니다.",
            value="",
            required=False,
        ),
        MessageTextInput(
            name="workflow_key",
            display_name="Workflow 키",
            info="Registry에서 실행할 고정 key입니다. 지정하면 inline 정의보다 우선하며 미등록 key는 오류입니다.",
            value="",
            required=False,
        ),
        MessageTextInput(
            name="workflow_registry_json",
            display_name="Workflow 후보 Registry JSON",
            info="00A Registry 로더가 질문 기준으로 제한한 workflow.registry.v1 후보 JSON입니다.",
            value="{}",
            required=False,
        ),
        MessageTextInput(
            name="user_question",
            display_name="사용자 원문 질문",
            info="등록 Workflow의 {{user_question}} 또는 ${user_question} 자리표시자에만 주입합니다.",
            value="",
            required=False,
        ),
        MultilineInput(
            name="allowed_tool_names",
            display_name="허용 Tool 이름",
            info="연결된 Tool 이름을 JSON 배열·쉼표·줄바꿈으로 적습니다. 비우면 이름 형식만 검증합니다.",
            value="",
            required=False,
        ),
        MultilineInput(
            name="tool_capabilities_json",
            display_name="Tool 결과 참조 capability",
            info="각 Tool의 result_ref 생성·선택 소비·필수 소비 계약 JSON입니다. Builder가 자동 입력합니다.",
            value="[]",
            required=False,
            advanced=True,
        ),
    ]
    outputs = [
        Output(name="workflow_plan", display_name="Workflow 계획", method="build_plan", types=["Data"], group_outputs=True),
        Output(name="loop_dataframe", display_name="Loop 반복 DataFrame", method="build_loop_dataframe", types=["DataFrame"], group_outputs=True),
        Output(name="loop_data_list", display_name="Loop Data 목록", method="build_loop_data_list", types=["Data"], group_outputs=True),
    ]

    # 함수 설명: `_result_once()`는 여러 group output이 같은 실행에서 서로 다른 run_id를 만들지 않도록 파싱 결과를 캐시합니다.
    def _result_once(self) -> dict[str, Any]:
        values = (
            getattr(self, "workflow_input", ""),
            getattr(self, "workflow_key", ""),
            getattr(self, "workflow_registry_json", ""),
            getattr(self, "user_question", ""),
            getattr(self, "allowed_tool_names", ""),
            getattr(self, "tool_capabilities_json", ""),
        )
        cache_key = tuple(_text(value) for value in values)
        if getattr(self, "_workflow_cache_key", None) != cache_key:
            self._workflow_cache_key = cache_key
            self._workflow_parse_result = parse_workflow_plan(
                values[0],
                values[1],
                values[2],
                values[3],
                values[4],
                tool_capabilities_value=values[5],
            )
        return self._workflow_parse_result

    # Langflow 출력 함수: 운영자 진단용 정규화 계획과 오류를 Data로 반환합니다.
    def build_plan(self) -> Data:
        result = deepcopy(self._result_once())
        self.status = result
        return Data(data=result)

    # Langflow 출력 함수: 기본 Loop Inputs 포트에 직접 연결할 한 단계당 한 행의 DataFrame을 반환합니다.
    def build_loop_dataframe(self) -> DataFrame:
        return DataFrame(_loop_rows(self._result_once()))

    # Langflow 출력 함수: Loop 구현 차이를 고려해 같은 단계들을 Data 목록으로도 반환합니다.
    def build_loop_data_list(self) -> list[Data]:
        return [Data(data=row) for row in _loop_rows(self._result_once())]

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 01 순차 Workflow 단계 실행기
# 역할: 기본 Langflow Loop의 현재 step에 지정된 Tool을 정확히 한 번 실행하고 이전 단계의 compact result_ref를 연결합니다.
# 주요 입력: Loop 현재 항목, 연결 Tool 목록, 세션 ID, observation 최대 바이트
# 주요 출력: Loop의 Looping 포트로 되돌릴 compact 단계 결과
# 처리 흐름: step/context 검증 -> dependency 확인 -> 정확한 Tool 선택 -> 단일 invoke -> 결과 축약 -> 다음 단계 context 저장
# 유지보수 포인트: builtins TTL registry는 flow/user/session/run별로 격리하며 전체 rows·trace·artifact.raw를 절대 저장하지 않습니다.
# =============================================================================

from __future__ import annotations

import asyncio
import builtins
import inspect
import json
import time
from copy import deepcopy
from typing import Any
from urllib.parse import urlsplit

from lfx.custom.custom_component.component import Component
from lfx.io import HandleInput, MessageTextInput, Output
from lfx.schema.data import Data

PLAN_CONTRACT_VERSION = "workflow.plan.v1"
TOOL_RESULT_CONTRACT_VERSION = "route_v3.tool_result.v1"
STEP_RESULT_CONTRACT_VERSION = "workflow.step_result.v1"
EXECUTION_CONTRACT_VERSION = "workflow.execution.v1"
DEFAULT_OBSERVATION_BYTES = 8192
MIN_OBSERVATION_BYTES = 1024
MAX_OBSERVATION_BYTES = 32 * 1024
SUMMARY_LIMIT = 1600
RESULT_REF_LIMIT = 1024
REGISTRY_TTL_SECONDS = 60 * 60
REGISTRY_MAX_CONTEXTS = 256
REGISTRY_ATTRIBUTE = "__metadata_route_v4_execution_registry__"
MAX_PUBLIC_URL_CHARS = 2_048


# 주요 함수: 단일 step의 dependency와 Tool 결과 계약을 검증하고 업데이트된 실행 context와 compact 결과를 반환합니다.
# Langflow 1.8.x의 Custom Component loader는 최상위 AsyncFunctionDef를 전역 scope에
# 등록하지 않으므로, 일반 함수가 내부 coroutine을 만들어 반환하는 형태를 사용합니다.
def execute_workflow_step(
    step_value: Any,
    tools_value: Any,
    execution_context: Any = None,
    session_id: Any = "",
    observation_byte_limit: Any = DEFAULT_OBSERVATION_BYTES,
) -> Any:
    # 함수 설명: `_run_step()`은 검증, Tool 단일 호출, 결과 기록을 하나의 await 가능한 실행 단위로 묶습니다.
    async def _run_step() -> dict[str, Any]:
        step = _step_payload(step_value)
        context = _execution_context(execution_context, step, session_id)
        limit = _bounded_int(
            observation_byte_limit,
            DEFAULT_OBSERVATION_BYTES,
            MIN_OBSERVATION_BYTES,
            MAX_OBSERVATION_BYTES,
        )
        validation_error = _step_execution_error(step, context)
        if validation_error:
            result = _fit_observation(_error_step_result(step, validation_error, "blocked"), limit)
            _record_result(context, result, stop=True)
            return {"step_result": result, "execution_context": context}

        dependency_error, upstream_ref = _dependency_handoff(step, context)
        if dependency_error:
            result = _fit_observation(_error_step_result(step, dependency_error, "blocked"), limit)
            _record_result(context, result, stop=str(step.get("on_error") or "stop") == "stop")
            return {"step_result": result, "execution_context": context}

        tool, tool_error = _select_exact_tool(tools_value, str(step.get("tool_name") or ""))
        if tool_error:
            result = _fit_observation(_error_step_result(step, tool_error, "error"), limit)
            _record_result(context, result, stop=str(step.get("on_error") or "stop") == "stop")
            return {"step_result": result, "execution_context": context}

        flow_tweak_data = {"question": str(step.get("question") or "").strip()}
        if str(step.get("handoff")) == "result_ref":
            flow_tweak_data["upstream_result_ref"] = upstream_ref
        # Langflow Run Flow Tool은 공개 question/ref를 최상위 인자로 받지 않고
        # 필수 `flow_tweak_data` 내부의 동적 InputSchema 값으로 받습니다.
        arguments = {"flow_tweak_data": flow_tweak_data}
        try:
            raw_result = await _invoke_tool_once(tool, arguments)
            contract, contract_error = _tool_result_contract(raw_result)
            if contract_error:
                result = _error_step_result(step, contract_error, "error")
            else:
                result = _compact_success_result(step, contract)
        except Exception as exc:
            result = _error_step_result(
                step,
                _issue("tool_execution_error", f"Tool 실행 중 오류가 발생했습니다: {exc}"),
                "error",
            )

        stop = str(result.get("status")) in {"error", "blocked"} and str(step.get("on_error")) == "stop"
        result = _fit_observation(result, limit)
        _record_result(context, result, stop=stop)
        return {"step_result": result, "execution_context": context}

    return _run_step()


# 함수 설명: `_step_payload()`는 Loop Data의 text JSON 또는 일반 dict에서 현재 단계 필드를 복원합니다.
def _step_payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    if hasattr(data, "to_dict") and not isinstance(data, dict):
        try:
            records = data.to_dict(orient="records")
            data = records[0] if len(records) == 1 else {}
        except Exception:
            data = {}
    if not isinstance(data, dict):
        text = getattr(value, "text", value)
        try:
            data = json.loads(str(text or ""))
        except (TypeError, ValueError, json.JSONDecodeError):
            data = {}
    text_value = data.get("text") if isinstance(data, dict) else None
    if isinstance(text_value, str):
        try:
            parsed = json.loads(text_value)
        except (TypeError, ValueError, json.JSONDecodeError):
            parsed = None
        if isinstance(parsed, dict):
            return parsed
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_execution_context()`는 기존 context를 복사하거나 첫 단계 정보를 이용해 새 workflow.execution.v1 context를 만듭니다.
def _execution_context(value: Any, step: dict[str, Any], session_id: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    if isinstance(data, dict) and isinstance(data.get("execution_context"), dict):
        data = data["execution_context"]
    if isinstance(data, dict) and data.get("contract_version") == EXECUTION_CONTRACT_VERSION:
        return deepcopy(data)
    return {
        "contract_version": EXECUTION_CONTRACT_VERSION,
        "workflow_run_id": str(step.get("workflow_run_id") or "").strip(),
        "workflow_key": str(step.get("workflow_key") or "").strip(),
        "session_id": str(session_id or "").strip(),
        "original_question": str(step.get("original_question") or "").strip(),
        "total_steps": _bounded_int(step.get("total_steps"), 1, 1, 4),
        "status": "running",
        "stop_requested": False,
        "execution_order": [],
        "results_by_step": {},
    }


# 함수 설명: `_step_execution_error()`는 run ID·순서·중복·중단 상태를 확인해 잘못된 Loop 진행을 fail-closed 처리합니다.
def _step_execution_error(step: dict[str, Any], context: dict[str, Any]) -> dict[str, Any] | None:
    if str(step.get("contract_version") or "") != PLAN_CONTRACT_VERSION:
        return _issue("invalid_step_contract", "Loop 항목의 contract_version이 workflow.plan.v1이 아닙니다.")
    step_id = str(step.get("step_id") or "").strip()
    run_id = str(step.get("workflow_run_id") or "").strip()
    if not step_id or not run_id:
        return _issue("step_identity_missing", "Loop 단계의 step_id 또는 workflow_run_id가 비어 있습니다.")
    if str(context.get("workflow_run_id") or "") != run_id:
        return _issue("workflow_run_mismatch", "다른 workflow_run_id의 실행 context가 전달되었습니다.")
    if step_id in _dict(context.get("results_by_step")):
        return _issue("duplicate_step_execution", f"같은 step_id를 다시 실행할 수 없습니다: {step_id}")
    if context.get("stop_requested") is True:
        return _issue("workflow_already_stopped", "앞 단계의 stop 정책으로 Workflow가 이미 중단되었습니다.")
    expected_index = len(_list(context.get("execution_order"))) + 1
    if _bounded_int(step.get("step_index"), 0, 0, 4) != expected_index:
        return _issue("unexpected_step_order", f"예상 step_index={expected_index}, 실제={step.get('step_index')}")
    return None


# 함수 설명: `_dependency_handoff()`는 모든 dependency 성공 여부와 단일 result_ref 전달 가능 여부를 검사합니다.
def _dependency_handoff(step: dict[str, Any], context: dict[str, Any]) -> tuple[dict[str, Any] | None, str]:
    dependencies = [str(item) for item in _list(step.get("depends_on")) if str(item or "").strip()]
    results = _dict(context.get("results_by_step"))
    for dependency in dependencies:
        result = results.get(dependency) if isinstance(results.get(dependency), dict) else None
        if result is None:
            return _issue("dependency_result_missing", f"dependency 실행 결과가 없습니다: {dependency}"), ""
        if str(result.get("status") or "") not in {"ok", "partial"}:
            return _issue("dependency_failed", f"dependency가 성공하지 않아 현재 단계를 실행하지 않습니다: {dependency}"), ""
    if str(step.get("handoff") or "none") != "result_ref":
        return None, ""
    if len(dependencies) != 1:
        return _issue("ambiguous_result_ref_handoff", "result_ref handoff에는 dependency가 정확히 하나 필요합니다."), ""
    source = _dict(results.get(dependencies[0]))
    result_ref = str(source.get("result_ref") or "").strip()
    if not result_ref or source.get("handoff_usable") is not True:
        return _issue("dependency_result_ref_unavailable", "dependency 결과에 사용할 수 있는 result_ref가 없습니다."), ""
    return None, result_ref


# 함수 설명: `_select_exact_tool()`은 대소문자 보정 없이 tool.name이 정확히 같은 Tool 하나만 허용합니다.
def _select_exact_tool(tools_value: Any, tool_name: str) -> tuple[Any | None, dict[str, Any] | None]:
    tools = _tools(tools_value)
    matches = [tool for tool in tools if str(getattr(tool, "name", "") or "").strip() == tool_name]
    if not matches:
        return None, _issue("tool_not_found", f"연결 Tool 목록에서 정확한 이름을 찾지 못했습니다: {tool_name}")
    if len(matches) > 1:
        return None, _issue("duplicate_tool_name", f"같은 이름의 Tool이 둘 이상 연결되었습니다: {tool_name}")
    return matches[0], None


# 함수 설명: `_tools()`는 단일 Tool, list, toolkit 형태를 평탄화하되 이름 없는 값은 제외합니다.
def _tools(value: Any) -> list[Any]:
    data = getattr(value, "data", value)
    if isinstance(data, dict):
        data = data.get("tools") or data.get("toolkit") or []
    values = list(data) if isinstance(data, (list, tuple, set)) else ([data] if data is not None else [])
    result: list[Any] = []
    for item in values:
        nested = getattr(item, "tools", None)
        if isinstance(nested, list):
            result.extend(tool for tool in nested if getattr(tool, "name", None))
        elif getattr(item, "name", None):
            result.append(item)
    return result


# 함수 설명: `_invoke_tool_once()`는 사용 가능한 첫 실행 인터페이스를 선택하고 실패 시 다른 방식으로 재호출하지 않습니다.
# 이 함수도 Langflow loader가 전역 helper로 보존하도록 일반 함수가 내부 coroutine을 반환합니다.
def _invoke_tool_once(tool: Any, arguments: dict[str, Any]) -> Any:
    # 함수 설명: `_run_tool()`은 선택된 Tool의 첫 번째 지원 인터페이스만 정확히 한 번 호출합니다.
    async def _run_tool() -> Any:
        ainvoke = getattr(tool, "ainvoke", None)
        if callable(ainvoke):
            return await ainvoke(deepcopy(arguments))
        arun = getattr(tool, "arun", None)
        if callable(arun):
            return await arun(**deepcopy(arguments))
        invoke = getattr(tool, "invoke", None)
        if callable(invoke):
            return await asyncio.to_thread(invoke, deepcopy(arguments))
        if callable(tool):
            result = tool(**deepcopy(arguments))
            return await result if inspect.isawaitable(result) else result
        raise TypeError("선택된 Tool에 ainvoke/arun/invoke/callable 실행 인터페이스가 없습니다.")

    return _run_tool()


# 함수 설명: `_tool_result_contract()`은 Tool 반환값에서 route_v3.tool_result.v1 계약만 꺼내고 자연어 추측 fallback을 금지합니다.
def _tool_result_contract(value: Any) -> tuple[dict[str, Any], dict[str, Any] | None]:
    data = getattr(value, "data", value)
    if isinstance(data, dict) and isinstance(data.get("tool_result"), dict):
        data = data["tool_result"]
    if not isinstance(data, dict):
        text = getattr(value, "text", value)
        try:
            data = json.loads(str(text or ""))
        except (TypeError, ValueError, json.JSONDecodeError):
            data = {}
    if not isinstance(data, dict) or str(data.get("contract_version") or "") != TOOL_RESULT_CONTRACT_VERSION:
        return {}, _issue("invalid_tool_result_contract", "Tool 결과가 route_v3.tool_result.v1 계약이 아닙니다.")
    status = str(data.get("status") or "").strip().lower()
    if status not in {"ok", "partial", "error"}:
        return {}, _issue("invalid_tool_result_status", f"Tool 결과 status가 올바르지 않습니다: {status}")
    return data, None


# 함수 설명: `_compact_success_result()`는 Tool 결과에서 최종 합성과 handoff에 필요한 필드만 step 결과로 복사합니다.
def _compact_success_result(step: dict[str, Any], contract: dict[str, Any]) -> dict[str, Any]:
    return {
        "contract_version": STEP_RESULT_CONTRACT_VERSION,
        "workflow_run_id": str(step.get("workflow_run_id") or ""),
        "workflow_key": str(step.get("workflow_key") or ""),
        "step_index": _bounded_int(step.get("step_index"), 0, 0, 4),
        "total_steps": _bounded_int(step.get("total_steps"), 0, 0, 4),
        "step_id": str(step.get("step_id") or ""),
        "tool_name": str(step.get("tool_name") or ""),
        "question": _clip(step.get("question"), 1000),
        "depends_on": deepcopy(_list(step.get("depends_on"))),
        "handoff": str(step.get("handoff") or "none"),
        "on_error": str(step.get("on_error") or "stop"),
        "status": str(contract.get("status") or "error"),
        "summary": _clip(contract.get("summary"), SUMMARY_LIMIT),
        "result_ref": _clip(contract.get("result_ref"), RESULT_REF_LIMIT),
        "result_ref_meta": _compact_ref_meta(contract.get("result_ref_meta")),
        "entity_ids": _compact_entity_ids(contract.get("entity_ids")),
        "artifacts": _compact_artifacts(contract.get("artifacts")),
        "handoff_usable": contract.get("handoff_usable") is True,
        "warnings": _compact_issues(contract.get("warnings")),
        "errors": _compact_issues(contract.get("errors")),
    }


# 함수 설명: `_error_step_result()`은 parser/dependency/Tool 오류를 같은 workflow.step_result.v1 구조로 만듭니다.
def _error_step_result(step: dict[str, Any], error: dict[str, Any], status: str) -> dict[str, Any]:
    return {
        "contract_version": STEP_RESULT_CONTRACT_VERSION,
        "workflow_run_id": str(step.get("workflow_run_id") or ""),
        "workflow_key": str(step.get("workflow_key") or ""),
        "step_index": _bounded_int(step.get("step_index"), 0, 0, 4),
        "total_steps": _bounded_int(step.get("total_steps"), 0, 0, 4),
        "step_id": str(step.get("step_id") or ""),
        "tool_name": str(step.get("tool_name") or ""),
        "question": _clip(step.get("question"), 1000),
        "depends_on": deepcopy(_list(step.get("depends_on"))),
        "handoff": str(step.get("handoff") or "none"),
        "on_error": str(step.get("on_error") or "stop"),
        "status": status,
        "summary": str(error.get("message") or "Workflow 단계 실행 오류"),
        "result_ref": "",
        "result_ref_meta": {},
        "entity_ids": [],
        "artifacts": [],
        "handoff_usable": False,
        "warnings": [],
        "errors": [deepcopy(error)],
    }


# 함수 설명: `_record_result()`는 compact 결과만 context에 기록하고 마지막 단계의 전체 실행 상태를 계산합니다.
def _record_result(context: dict[str, Any], result: dict[str, Any], *, stop: bool) -> None:
    step_id = str(result.get("step_id") or "")
    context.setdefault("results_by_step", {})[step_id] = deepcopy(result)
    context.setdefault("execution_order", []).append(step_id)
    if stop:
        context["stop_requested"] = True
        context["status"] = "stopped"
    total_steps = _bounded_int(context.get("total_steps") or result.get("total_steps"), 0, 0, 4)
    if len(context.get("execution_order", [])) >= total_steps:
        statuses = [str(item.get("status") or "") for item in context.get("results_by_step", {}).values() if isinstance(item, dict)]
        if statuses and all(status == "ok" for status in statuses):
            context["status"] = "complete"
        elif any(status in {"ok", "partial"} for status in statuses):
            context["status"] = "partial"
        else:
            context["status"] = "error"


# 함수 설명: `_fit_observation()`은 summary/entity/issues를 단계적으로 줄여 직렬화 결과가 설정 바이트를 넘지 않게 합니다.
def _fit_observation(value: dict[str, Any], byte_limit: int) -> dict[str, Any]:
    result = deepcopy(value)
    if _json_bytes(result) + 32 <= byte_limit:
        return _stamp_observation_bytes(result, byte_limit)
    result["summary"] = _clip(result.get("summary"), 800)
    result["warnings"] = _compact_issues(result.get("warnings"), count=2, text_limit=200)
    result["errors"] = _compact_issues(result.get("errors"), count=2, text_limit=200)
    result["entity_ids"] = _compact_entity_ids(result.get("entity_ids"), entity_limit=3, value_limit=5)
    result["artifacts"] = _compact_artifacts(result.get("artifacts"), count=2)
    if _json_bytes(result) > byte_limit:
        result["summary"] = _clip(result.get("summary"), 300)
        result["result_ref_meta"] = _compact_ref_meta(result.get("result_ref_meta"), column_limit=5)
        result["entity_ids"] = []
        result["warnings"] = _compact_issues(result.get("warnings"), count=1, text_limit=120)
        result["errors"] = _compact_issues(result.get("errors"), count=1, text_limit=120)
    if _json_bytes(result) > byte_limit:
        result = {
            key: result.get(key)
            for key in (
                "contract_version",
                "workflow_run_id",
                "step_index",
                "total_steps",
                "step_id",
                "tool_name",
                "status",
                "summary",
                "result_ref",
                "artifacts",
                "handoff_usable",
                "errors",
            )
        }
        result["summary"] = _clip(result.get("summary"), 160)
        result["result_ref"] = _clip(result.get("result_ref"), 256)
    return _stamp_observation_bytes(result, byte_limit)


# 함수 설명: `_stamp_observation_bytes()`는 크기 필드 자체를 포함한 최종 JSON이 상한 안에 있도록 마지막 여유를 확보합니다.
def _stamp_observation_bytes(value: dict[str, Any], byte_limit: int) -> dict[str, Any]:
    result = deepcopy(value)
    result["observation_bytes"] = 0
    result["observation_bytes"] = _json_bytes(result)
    if _json_bytes(result) <= byte_limit:
        return result
    result["summary"] = _clip(result.get("summary"), 100)
    result["errors"] = _compact_issues(result.get("errors"), count=1, text_limit=80)
    result["warnings"] = []
    result["artifacts"] = _compact_artifacts(result.get("artifacts"), count=1, path_limit=512, title_limit=100)
    result["observation_bytes"] = _json_bytes(result)
    if _json_bytes(result) <= byte_limit:
        return result
    # 최소 상한 1KB에서도 identity/status/ref는 충분히 들어가며, 마지막 수단으로 크기 표기 필드를 제거합니다.
    result.pop("observation_bytes", None)
    return result


# 함수 설명: `_compact_ref_meta()`는 다음 단계와 최종 설명에 필요한 결과 건수·컬럼 정보만 보존합니다.
def _compact_ref_meta(value: Any, column_limit: int = 20) -> dict[str, Any]:
    meta = value if isinstance(value, dict) else {}
    columns = [str(item) for item in _list(meta.get("columns")) if str(item or "").strip()][:column_limit]
    return {
        key: deepcopy(item)
        for key, item in {
            "role": meta.get("role"),
            "row_count": meta.get("row_count"),
            "columns": columns,
            "source_alias": meta.get("source_alias"),
            "dataset_key": meta.get("dataset_key"),
        }.items()
        if item not in (None, "", [], {})
    }


# 함수 설명: `_safe_artifact_path()`는 외부 URL·절대 경로·drive path·경로 순회를 거부하고 `flow_id/file.html`만 반환합니다.
def _safe_artifact_path(value: Any, path_limit: int = 1024) -> str:
    path = _clip(value, path_limit).replace("\\", "/")
    parts = path.split("/")
    if (
        not path
        or path.startswith("/")
        or "://" in path
        or (len(path) >= 2 and path[1] == ":")
        or len(parts) != 2
        or any(part in {"", ".", ".."} for part in parts)
        or any(marker in path for marker in ("?", "#", "\x00"))
        or not parts[-1].lower().endswith(".html")
    ):
        return ""
    return path


# 함수 설명: 단계 상태에 보존할 Report API 링크를 절대 http(s) URL로 제한합니다.
def _safe_public_url(value: Any) -> str:
    candidate = _clip(value, MAX_PUBLIC_URL_CHARS)
    if not candidate or any(ord(character) < 32 for character in candidate):
        return ""
    try:
        parsed = urlsplit(candidate)
    except ValueError:
        return ""
    if parsed.scheme.lower() not in {"http", "https"} or not parsed.hostname:
        return ""
    if parsed.username is not None or parsed.password is not None or parsed.fragment:
        return ""
    return candidate


# 함수 설명: `_compact_artifacts()`는 검증된 HTML 파일 descriptor의 허용 필드만 남기고 raw HTML/content를 단계 상태에서 제거합니다.
def _compact_artifacts(
    value: Any,
    count: int = 2,
    path_limit: int = 1024,
    title_limit: int = 180,
) -> list[dict[str, Any]]:
    result: list[dict[str, Any]] = []
    seen_paths: set[str] = set()
    for item in _list(value)[:count]:
        if not isinstance(item, dict):
            continue
        artifact_type = _clip(item.get("artifact_type"), 40).lower()
        mime_type = _clip(item.get("mime_type"), 80).lower().split(";", 1)[0].strip()
        path = _safe_artifact_path(item.get("path"), path_limit)
        download_name = _clip(item.get("download_name"), 180)
        if artifact_type != "html_chart" or mime_type != "text/html" or not path or path in seen_paths:
            continue
        if "/" in download_name or "\\" in download_name or not download_name.lower().endswith(".html"):
            continue
        descriptor: dict[str, Any] = {
            "artifact_type": artifact_type,
            "title": _clip(item.get("title") or download_name.rsplit(".", 1)[0], title_limit),
            "mime_type": mime_type,
            "download_name": download_name,
            "path": path,
        }
        report_id = _clip(item.get("report_id"), 160)
        view_url = _safe_public_url(item.get("view_url"))
        download_url = _safe_public_url(item.get("download_url"))
        expires_at = _clip(item.get("expires_at"), 80)
        if report_id:
            descriptor["report_id"] = report_id
        if view_url:
            descriptor["view_url"] = view_url
        if download_url:
            descriptor["download_url"] = download_url
        if expires_at:
            descriptor["expires_at"] = expires_at
        if view_url or download_url:
            try:
                ttl_hours = max(1, min(int(item.get("ttl_hours") or 24), 168))
            except (TypeError, ValueError):
                ttl_hours = 24
            descriptor["ttl_hours"] = ttl_hours
        try:
            size_bytes = int(item.get("size_bytes")) if item.get("size_bytes") is not None else None
        except (TypeError, ValueError):
            size_bytes = None
        if size_bytes is not None and size_bytes >= 0:
            descriptor["size_bytes"] = size_bytes
        chart_type = _clip(item.get("chart_type"), 40).lower()
        if chart_type:
            descriptor["chart_type"] = chart_type
        x_column = _clip(item.get("x_column"), 120)
        if x_column:
            descriptor["x_column"] = x_column
        y_columns = [_clip(column, 120) for column in _list(item.get("y_columns"))[:8] if _clip(column, 120)]
        if y_columns:
            descriptor["y_columns"] = y_columns
        for count_name in ("row_count", "plotted_row_count"):
            try:
                count_value = int(item.get(count_name)) if item.get(count_name) is not None else None
            except (TypeError, ValueError):
                count_value = None
            if count_value is not None and count_value >= 0:
                descriptor[count_name] = count_value
        result.append(descriptor)
        seen_paths.add(path)
    return result


# 함수 설명: `_compact_entity_ids()`는 식별자 종류와 작은 preview만 남기고 전체 ID 목록을 result_ref 뒤에 숨깁니다.
def _compact_entity_ids(value: Any, entity_limit: int = 8, value_limit: int = 20) -> list[dict[str, Any]]:
    result: list[dict[str, Any]] = []
    for item in _list(value)[:entity_limit]:
        if not isinstance(item, dict):
            continue
        values = deepcopy(_list(item.get("values"))[:value_limit])
        result.append(
            {
                "entity_type": _clip(item.get("entity_type"), 80),
                "column": _clip(item.get("column"), 100),
                "values": values,
                "observed_count": len(values),
                "total_count": item.get("total_count"),
                "complete": item.get("complete") is True and len(_list(item.get("values"))) <= value_limit,
            }
        )
    return result


# 함수 설명: `_compact_issues()`는 warning/error를 짧은 type/message object로 제한합니다.
def _compact_issues(value: Any, count: int = 5, text_limit: int = 320) -> list[dict[str, Any]]:
    result: list[dict[str, Any]] = []
    for item in _list(value)[:count]:
        if isinstance(item, dict):
            result.append({"type": _clip(item.get("type"), 100), "message": _clip(item.get("message"), text_limit)})
        else:
            result.append({"type": "message", "message": _clip(item, text_limit)})
    return result


# 함수 설명: `_registry()`는 프로세스 builtins에 TTL registry 하나를 만들고 만료·최대 개수 정리를 수행합니다.
def _registry() -> dict[str, dict[str, Any]]:
    registry = getattr(builtins, REGISTRY_ATTRIBUTE, None)
    if not isinstance(registry, dict):
        registry = {}
        setattr(builtins, REGISTRY_ATTRIBUTE, registry)
    now = time.time()
    for key in list(registry):
        entry = registry.get(key) if isinstance(registry.get(key), dict) else {}
        if now - float(entry.get("updated_at") or 0) > REGISTRY_TTL_SECONDS:
            registry.pop(key, None)
    if len(registry) > REGISTRY_MAX_CONTEXTS:
        ordered = sorted(registry, key=lambda key: float(_dict(registry.get(key)).get("updated_at") or 0))
        for key in ordered[: len(registry) - REGISTRY_MAX_CONTEXTS]:
            registry.pop(key, None)
    return registry


# 함수 설명: `_registry_key()`는 사용자·Flow·세션·run ID를 결합해 동시 실행 context가 섞이지 않는 key를 만듭니다.
def _registry_key(component: Any, step: dict[str, Any], explicit_session_id: Any) -> str:
    graph = getattr(component, "graph", None)
    user_id = str(getattr(component, "user_id", "") or "anonymous")
    flow_id = str(getattr(graph, "flow_id", "") or "flow")
    session_id = str(explicit_session_id or getattr(graph, "session_id", "") or "session")
    run_id = str(step.get("workflow_run_id") or "run")
    return "|".join((user_id, flow_id, session_id, run_id))


# 함수 설명: `_load_registry_context()`는 첫 단계에서 이전 동명 run을 초기화하고 이후 단계에서는 저장된 compact context만 반환합니다.
def _load_registry_context(component: Any, key: str, step: dict[str, Any], session_id: Any) -> dict[str, Any]:
    registry = _registry()
    if _bounded_int(step.get("step_index"), 0, 0, 4) == 1:
        registry.pop(key, None)
    entry = registry.get(key) if isinstance(registry.get(key), dict) else {}
    context = entry.get("context") if isinstance(entry.get("context"), dict) else None
    return _execution_context(context, step, session_id)


# 함수 설명: `_save_or_cleanup_registry_context()`는 중간 단계만 TTL 저장하고 마지막 Loop 항목 처리 후 즉시 정리합니다.
def _save_or_cleanup_registry_context(key: str, context: dict[str, Any], step: dict[str, Any]) -> None:
    registry = _registry()
    if _bounded_int(step.get("step_index"), 0, 0, 4) >= _bounded_int(step.get("total_steps"), 0, 0, 4):
        registry.pop(key, None)
        return
    registry[key] = {"updated_at": time.time(), "context": deepcopy(context)}


# 함수 설명: `_json_bytes()`는 observation 크기 제한에 사용할 UTF-8 JSON 바이트 수를 계산합니다.
def _json_bytes(value: Any) -> int:
    return len(json.dumps(value, ensure_ascii=False, separators=(",", ":"), default=str).encode("utf-8"))


# 함수 설명: `_bounded_int()`는 화면 숫자 입력을 지정한 최소·최대 범위의 정수로 정규화합니다.
def _bounded_int(value: Any, default: int, lower: int, upper: int) -> int:
    try:
        parsed = int(str(value).strip()) if str(value or "").strip() else default
    except Exception:
        parsed = default
    return max(lower, min(parsed, upper))


# 함수 설명: `_clip()`은 문자열을 지정 길이로 자르고 초과 여부를 말줄임으로 표시합니다.
def _clip(value: Any, limit: int) -> str:
    text = str(value or "").strip()
    return text if len(text) <= limit else text[: max(0, limit - 1)].rstrip() + "…"


# 함수 설명: `_dict()`는 dict가 아닌 값을 빈 dict로 바꿔 안전한 key 접근을 보장합니다.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# 함수 설명: `_list()`는 list가 아닌 값을 빈 목록으로 바꿔 반복 경계를 명확히 합니다.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# 함수 설명: `_issue()`는 executor 오류를 type/message가 있는 표준 dict로 구성합니다.
def _issue(issue_type: str, message: str, **extra: Any) -> dict[str, Any]:
    return {"type": issue_type, "message": message, **extra}


# Langflow 컴포넌트 클래스: 기본 Loop의 Item과 Looping 사이에서 정확히 한 단계만 실행합니다.
class SequentialWorkflowStepExecutor(Component):
    display_name = "01 순차 Workflow 단계 실행기"
    description = "Loop 현재 step의 정확한 Tool 하나를 실행하고 compact 결과/ref만 다음 단계에 보존합니다."
    name = "SequentialWorkflowStepExecutor"
    icon = "Workflow"

    inputs = [
        HandleInput(
            name="loop_item",
            display_name="Loop 현재 항목",
            info="00 파서의 Loop DataFrame/Data 목록을 기본 Loop가 한 행씩 전달한 Data입니다.",
            input_types=["Data"],
            required=True,
        ),
        HandleInput(
            name="tools",
            display_name="Workflow Tool 목록",
            info="Workflow compact result 계약을 반환하는 Tool들을 연결합니다.",
            input_types=["Tool"],
            is_list=True,
            required=True,
        ),
        MessageTextInput(
            name="session_id",
            display_name="세션 ID",
            info="비우면 현재 graph session_id를 사용합니다.",
            value="",
            required=False,
            advanced=True,
        ),
        MessageTextInput(
            name="observation_byte_limit",
            display_name="단계 결과 최대 바이트",
            value=str(DEFAULT_OBSERVATION_BYTES),
            required=False,
            advanced=True,
        ),
    ]
    outputs = [Output(name="step_result", display_name="단계 결과", method="build_step_result", types=["Data"])]

    # Langflow 출력 함수: registry에서 현재 run context를 복원하고 한 번 실행한 compact 결과를 Looping 포트로 반환합니다.
    async def build_step_result(self) -> Data:
        step = _step_payload(getattr(self, "loop_item", None))
        explicit_session = str(getattr(self, "session_id", "") or "").strip()
        graph_session = str(getattr(getattr(self, "graph", None), "session_id", "") or "").strip()
        resolved_session = explicit_session or graph_session
        key = _registry_key(self, step, resolved_session)
        context = _load_registry_context(self, key, step, resolved_session)
        execution = await execute_workflow_step(
            step,
            getattr(self, "tools", None),
            context,
            resolved_session,
            getattr(self, "observation_byte_limit", DEFAULT_OBSERVATION_BYTES),
        )
        result = execution["step_result"]
        updated_context = execution["execution_context"]
        _save_or_cleanup_registry_context(key, updated_context, step)
        self.status = result
        return Data(data=result)

