            value=True,
            advanced=True,
        ),
        StrInput(
            name="tool_name",
            display_name="도구 이름",
            info="Agent가 호출할 영문 도구 이름입니다.",
            required=True,
        ),
        MultilineInput(
            name="tool_description",
            display_name="도구 설명",
            info="Agent가 단일 또는 연계 호출 순서를 판단할 수 있도록 입력과 결과 범위를 설명합니다.",
            required=True,
        ),
        MultilineInput(
            name="preferred_output_names",
            display_name="우선 최종 출력 이름",
            info=(
                "하위 Flow에서 우선 사용할 terminal 출력 이름을 순서대로 입력합니다. "
                "쉼표 또는 줄바꿈으로 구분하며, 비우면 유일한 Data 출력을 자동 선택합니다."
            ),
            value="",
            required=False,
            advanced=True,
        ),
        BoolInput(
            name="return_direct",
